import androidx.biometric.BiometricPrompt
import androidx.core.content.edit
import androidx.fragment.app.Fragment

private fun Fragment.showBiometricPrompt() {
    val biometricPrompt = BiometricPrompt(this, requireContext().mainExecutor) { _, _ ->
        requireContext().getSharedPreferences("auth", Context.MODE_PRIVATE).edit {
            putBoolean("authenticated", true)
        }
        startActivity(Intent(requireContext(), DashboardActivity::class.java))
        requireActivity().finish()
    }

    val promptInfo = BiometricPrompt.PromptInfo.Builder()
        .setTitle("Fingerprint Authentication")
        .setSubtitle("Please authenticate using your fingerprint")
        .setNegativeButtonText("Use Password")
        .build()

    biometricPrompt.authenticate(promptInfo)
}